class TrieNode {
    children: (TrieNode | null)[] = [null, null];
}

class Trie {
    root: TrieNode;
    count: number;
    constructor() {
        this.root = new TrieNode();
        this.count = 0;
    }
    insert(num: number): void {
        let node = this.root;
        for (let i = 31; i >= 0; i--) {
            const bit = (num >>> i) & 1;
            if (node.children[bit] === null) {
                node.children[bit] = new TrieNode();
            }
            node = node.children[bit]!;
        }
        this.count++;
    }
    getMinXor(num: number): number {
        if (this.count === 0) {
            return Infinity;
        }
        let node = this.root;
        let min_xor = 0;
        for (let i = 31; i >= 0; i--) {
            const bit = (num >>> i) & 1;
            if (node.children[bit] !== null) {
                node = node.children[bit]!;
            } else if (node.children[1 - bit] !== null) {
                min_xor |= (1 << i);
                node = node.children[1 - bit]!;
            } else {
                break;
            }
        }
        return min_xor;
    }
}

function solve(nums: number[], k: number): number {
    const n = nums.length;
    let pre = new Array(n + 1);
    pre[0] = 0;
    for (let i = 0; i < n; i++) {
        pre[i + 1] = pre[i] ^ nums[i];
