    let low = 0;
    let high = (1 << 31) - 1;

    const feasible = (threshold: number): boolean => {
        let dp_prev = new Array(n + 1).fill(false);
        dp_prev[0] = true;

        for (let layer = 1; layer <= k; layer++) {
            let dp_curr = new Array(n + 1).fill(false);
            let trie = new Trie();

            for (let i = layer; i <= n; i++) {
                if (dp_prev[i - 1]) {
                    trie.insert(pre[i - 1]);
                }
                if (trie.count > 0) {
                    const min_xor = trie.getMinXor(pre[i]);
                    if (min_xor <= threshold) {
                        dp_curr[i] = true;
                    }
                }
            }
            dp_prev = dp_curr;
        }
        return dp_prev[n];
    };

    while (low < high) {
        let mid = Math.floor((low + high) / 2);
        if (feasible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
```

### Explanation
